mapper.select:
select document_assignment_id, company_id, document_id, assignee_user_id, assigned_by_user_id, status, assigned_at, updated_at
from document_assignments
where document_assignment_id = #{documentAssignmentId,jdbcType=VARCHAR}

select document_assignment_id, company_id, document_id, assignee_user_id, assigned_by_user_id, status, assigned_at, updated_at
from document_assignments
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ASSIGNED'
order by assigned_at desc
limit #{limit,jdbcType=INTEGER}

select document_assignment_id, company_id, document_id, assignee_user_id, assigned_by_user_id, status, assigned_at, updated_at
from document_assignments
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and assignee_user_id = #{assigneeUserId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ASSIGNED'
limit 1

select document_assignment_id, company_id, document_id, assignee_user_id, assigned_by_user_id, status, assigned_at, updated_at
from document_assignments
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and assignee_user_id = #{assigneeUserId,jdbcType=VARCHAR}
order by updated_at desc nulls last, assigned_at desc
limit 1
